{
  "translations": [
    {
      "block_id": "p37_b1",
      "translation": "As of December 31, 2020, the total fixed income investments (including debt securities, loans and time deposits) held by policyholders and shareholders amounted to"
    },
    {
      "block_id": "p37_b2",
      "translation": "USD 204.418 billion, compared to USD 175.501 billion as of December 31, 2019."
    },
    {
      "block_id": "p37_b3",
      "translation": "Overview\nFinancial and Operational Review\nCorporate Governance\nOther Information\nFinancial Statements"
    },
    {
      "block_id": "p37_b4",
      "translation": "As of December 31, 2020, government bonds and other government and government agency bonds represented 43% of fixed income investments, compared to"
    },
    {
      "block_id": "p37_b5",
      "translation": "44% as of December 31, 2019. As of December 31, 2020, corporate bonds and structured securities represented 53% of fixed income investments, compared to 50% as of December 31, 2019."
    },
    {
      "block_id": "p37_b6",
      "translation": "The average credit rating of our fixed income investment portfolio (excluding government bonds) remained stable at A- compared to December 31, 2019. Our corporate"
    },
    {
      "block_id": "p37_b7",
      "translation": "bond portfolio is diversified with over 1,500 issuers and an average holding size of USD 67 million. As of December 31, 2020, we held investments"
    },
    {
      "block_id": "p37_b8",
      "translation": "below investment grade or unrated bonds of USD 3.7 billion, representing 2% of the total bond portfolio. Bonds below USD 600 million (representing 0.3% of the total bond portfolio)"
    },
    {
      "block_id": "p37_b9",
      "translation": "were downgraded below investment grade, and we recorded no impairments in 2020, reflecting the overall quality of our investment portfolio."
    },
    {
      "block_id": "p37_b10",
      "translation": "As of December 31, 2020, the total equity securities held by policyholders and shareholders amounted to USD 30.950 billion, compared to"
    },
    {
      "block_id": "p37_b11",
      "translation": "USD 26.221 billion as of December 31, 2019. The book value of equity securities increased by USD 4.729 billion, primarily driven by increased new purchases of equity securities from business growth. Of"
    },
    {
      "block_id": "p37_b12",
      "translation": "these equity securities, USD 23.892 billion were held by dividend funds and other dividend businesses with specific asset portfolios."
    },
    {
      "block_id": "p37_b13",
      "translation": "Cash and cash equivalents increased by USD 1.678 billion to USD 5.619 billion as of December 31, 2020, compared to USD 3.941 billion"
    },
    {
      "block_id": "p37_b14",
      "translation": "as of December 31, 2019. The increase primarily reflects balanced reallocation of the investment portfolio and optimization of time deposits into more liquid investments."
    },
    {
      "block_id": "p37_b15",
      "translation": "As of December 31, 2020, investment properties and properties held for own use by policyholders and shareholders totaled USD 6.624 billion, compared to USD 6.894 billion as of December 31,"
    },
    {
      "block_id": "p37_b16",
      "translation": "2019."
    },
    {
      "block_id": "p37_b17",
      "translation": "Deferred acquisition and initiation costs increased from USD 26.328 billion as of December 31, 2019 to USD 27.915 billion as of December 31, 2020, primarily due to"
    },
    {
      "block_id": "p37_b18",
      "translation": "new sales."
    },
    {
      "block_id": "p37_b19",
      "translation": "Other assets increased from USD 15.666 billion as of December 31, 2019 to USD 16.481 billion as of December 31, 2020, primarily reflecting an increase in"
    },
    {
      "block_id": "p37_b20",
      "translation": "reinsurance receivables."
    },
    {
      "block_id": "p37_b21",
      "translation": "Liabilities"
    },
    {
      "block_id": "p37_b22",
      "translation": "Total liabilities increased from USD 228.737 billion as of December 31, 2019 to USD 262.453 billion as of December 31, 2020."
    },
    {
      "block_id": "p37_b23",
      "translation": "Insurance and investment contract liabilities increased from USD 204.454 billion as of December 31, 2019 to USD 235.952 billion as of December 31, 2020, reflecting"
    },
    {
      "block_id": "p37_b24",
      "translation": "growth in the active policy portfolio and favorable foreign exchange movements."
    },
    {
      "block_id": "p37_b25",
      "translation": "Borrowings increased to USD 8.559 billion as of December 31, 2020 due to net proceeds of USD 2.792 billion from the issuance of medium-term notes and securities during the year. The leverage"
    },
    {
      "block_id": "p37_b26",
      "translation": "ratio (defined as borrowings expressed as a percentage of total borrowings and equity) was 11.9%, compared to 9.4% as of December 31, 2019."
    },
    {
      "block_id": "p37_b27",
      "translation": "Other liabilities were USD 17.942 billion as of December 31, 2020, compared to USD 18.526 billion as of December 31, 2019, reflecting settlement of USD 839 million related to the CMLA acquisition,"
    },
    {
      "block_id": "p37_b28",
      "translation": "offset by an increase in deferred tax liabilities."
    },
    {
      "block_id": "p37_b29",
      "translation": "Details of commitments and contingent liabilities are set out in Note 43 to the consolidated financial statements."
    },
    {
      "block_id": "p37_b30",
      "translation": "2020 Annual Report\n035"
    }
  ]
}
